export type Input = {
    /** Starting X coordinate on the desktop screenshot. */
    from_x: number;
    /** Starting Y coordinate on the desktop screenshot. */
    from_y: number;
    /** Ending X coordinate on the desktop screenshot. */
    to_x: number;
    /** Ending Y coordinate on the desktop screenshot. */
    to_y: number;
    /** Optional key chord to hold during the drag, using the same format as `press_key()`. */
    key?: string;
};
export type Return = Promise<void>;
/** Drag from one desktop coordinate to another. */
export type Function = (input: Input) => Return;
